def handle_item(request, item_id):
    """Handle /items/<id> endpoint."""
    if request.method == 'GET':
        item = _items_store.get(item_id)
        if not item:
            return make_response({
                'error': 'Not Found',
                'message': f'Item with id {item_id} not found'
            }, 404)
        return make_response({'data': item})

    elif request.method == 'PUT':
        if item_id not in _items_store:
            return make_response({
                'error': 'Not Found',
                'message': f'Item with id {item_id} not found'
            }, 404)

        request_json = request.get_json(silent=True)
        if not request_json:
            return make_response({
                'error': 'Bad Request',
                'message': 'Request body must be valid JSON'
            }, 400)

        updated_item = {
            'id': item_id,
            'name': request_json.get('name', _items_store[item_id]['name']),
            'description': request_json.get('description', _items_store[item_id]['description']),
            'price': request_json.get('price', _items_store[item_id]['price'])
        }
        _items_store[item_id] = updated_item

        return make_response({
            'data': updated_item,
            'message': 'Item updated successfully'
        })

    elif request.method == 'PATCH':
        if item_id not in _items_store:
            return make_response({
                'error': 'Not Found',
                'message': f'Item with id {item_id} not found'
            }, 404)

        request_json = request.get_json(silent=True)
        if not request_json:
            return make_response({
                'error': 'Bad Request',
                'message': 'Request body must be valid JSON'
            }, 400)

        current_item = _items_store[item_id]
        for key, value in request_json.items():
            if key != 'id' and key in current_item:
                current_item[key] = value
        _items_store[item_id] = current_item

        return make_response({
            'data': current_item,
            'message': 'Item patched successfully'
        })

    elif request.method == 'DELETE':
        if item_id not in _items_store:
            return make_response({
                'error': 'Not Found',
                'message': f'Item with id {item_id} not found'
            }, 404)

        deleted_item = _items_store.pop(item_id)
        return make_response({
            'data': deleted_item,
            'message': 'Item deleted successfully'
        })

    else:
        return make_response({
            'error': 'Method Not Allowed',
            'message': f'Method {request.method} not allowed on /items/{item_id}'
        }, 405)


